import React from 'react';

const Cultura = ({ sitios }) => {
    return (
        <div style={{ padding: '20px', textAlign: 'center' }}>
            <h1>Sitios Culturales de La Paz</h1>
            <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', gap: '20px', marginTop: '20px' }}>
                {sitios && sitios.length > 0 ? (
                    sitios.map((sitio) => (
                        <div key={sitio.id_sitio || sitio.id} style={{ 
                            border: '1px solid #ddd', 
                            padding: '15px', 
                            borderRadius: '10px', 
                            width: '300px',
                            boxShadow: '0 4px 8px rgba(0,0,0,0.1)'
                        }}>
                            <h2 style={{ color: '#e74c3c' }}>{sitio.nombre || sitio.NOMBRE}</h2>
                            <p>{sitio.descripcion || sitio.DESCRIPCION}</p>
                            <small>📍 {sitio.direccion || sitio.DIRECCION}</small>
                        </div>
                    ))
                ) : (
                    <div style={{ marginTop: '50px' }}>
                        <h3>No se encontraron datos</h3>
                        <p>Asegúrate de haber ejecutado los INSERT en PostgreSQL.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Cultura;
